export function KrtcMapSvg({ activeTrains }) {
    const mapContainerRef = useRef(null);
    const [stationCoordsRegistry, setStationCoordsRegistry] = useState({});
    const [isMapReady, setIsMapReady] = useState(false);

    // ==========================================
    // STEP 1: SCAN THE MAP ONCE AT STARTUP
    // ==========================================
    useEffect(() => {
        if (!mapContainerRef.current) return;

        // Inject the raw SVG code
        mapContainerRef.current.innerHTML = rawKrtcSvg;
        
        const svgElement = mapContainerRef.current.querySelector('svg');
        if (!svgElement) return;

        // ✨ RESTORED FIX 1: Bring back the ViewBox and size limits!
        svgElement.setAttribute('width', '100%');
        svgElement.setAttribute('height', '100%');
        svgElement.setAttribute('viewBox', '0 0 1400 2100');
        
        // ✨ RESTORED FIX 2: Strip the broken KRTC camera offset that flings the map off-screen!
        const viewportG = svgElement.querySelector('.svg-pan-zoom_viewport');
        if (viewportG) {
            viewportG.removeAttribute('transform');
            viewportG.removeAttribute('style');
        }

        // Clean up static KRTC train images so they don't clutter your replay
        const oldKrtcTrains = svgElement.querySelectorAll('image.rcarimg, image.ocarimg');
        oldKrtcTrains.forEach(img => img.remove());

        // We wait 50ms to ensure the browser has fully drawn the map before calculating coordinates
        setTimeout(() => {
            const registry = {};
            const allElements = svgElement.querySelectorAll('[id]');

            allElements.forEach(el => {
                const rawId = el.id.toLowerCase().trim();
                const match = rawId.match(/[a-z]+\d+[a-z]*/);
                
                if (match) {
                    const stationCode = match[0];
                    try {
                        const bbox = el.getBBox();
                        if (bbox.width > 0 || bbox.height > 0) {
                            let cx = bbox.x + (bbox.width / 2);
                            let cy = bbox.y + (bbox.height / 2);
                            
                            if (el.tagName === 'circle') {
                                cx = parseFloat(el.getAttribute('cx')) || cx;
                                cy = parseFloat(el.getAttribute('cy')) || cy;
                            }

                            registry[stationCode] = { x: cx, y: cy };
                        }
                    } catch (e) {
                        // Suppress errors for hidden elements
                    }
                }
            });

            console.log("📍 Station Coordinate Registry Built:", registry);
            setStationCoordsRegistry(registry);
            setIsMapReady(true);
        }, 50);
    }, []);

    // ==========================================
    // STEP 2: LIGNTNING-FAST TRAIN PLOTTER LOOP
    // ==========================================
    useEffect(() => {
        if (!isMapReady) return;

        const svgElement = mapContainerRef.current?.querySelector('svg');
        if (!svgElement) return;

        const targetLayer = svgElement.querySelector('.svg-pan-zoom_viewport') || svgElement;

        // Clean up old trains
        const oldMarkers = svgElement.querySelectorAll('.replay-train-marker');
        oldMarkers.forEach(marker => marker.remove());

        activeTrains.forEach(train => {
            if (!train.station) return;
            
            const cleanStation = train.station.toLowerCase().trim();
            let cx = 0, cy = 0;
            let coordinatesFound = false;
            let isEnRoute = false;

            // Scenario A: At a station
            if (stationCoordsRegistry[cleanStation]) {
                cx = stationCoordsRegistry[cleanStation].x;
                cy = stationCoordsRegistry[cleanStation].y;
                coordinatesFound = true;
            } 
            // Scenario B: Moving between stations (Fixed off-roading!)
            else {
                const transitTokens = cleanStation.match(/[a-z]{1,2}\d+a?/g);
                if (transitTokens && transitTokens.length >= 1) {
                    // Snap it safely to the station it just departed from
                    const startStation = stationCoordsRegistry[transitTokens[0]];
                    if (startStation) {
                        cx = startStation.x;
                        cy = startStation.y;
                        coordinatesFound = true;
                        isEnRoute = true; // Flag it so we can change its appearance
                    }
                }
            }

            if (coordinatesFound) {
                const markerGroup = document.createElementNS("http://www.w3.org/2000/svg", "g");
                markerGroup.setAttribute("class", "replay-train-marker");

                const markerColor = cleanStation.startsWith('o') ? '#dd6b20' : '#e53e3e';

                const trainDot = document.createElementNS("http://www.w3.org/2000/svg", "circle");
                trainDot.setAttribute("cx", cx);
                trainDot.setAttribute("cy", cy);
                trainDot.setAttribute("r", "16"); 
                trainDot.setAttribute("fill", markerColor);
                trainDot.setAttribute("stroke", "#ffffff");
                
                // ✨ FIX: If it's between stations, make it dashed and slightly see-through!
                if (isEnRoute) {
                    trainDot.setAttribute("stroke-dasharray", "4 2");
                    trainDot.setAttribute("stroke-width", "4");
                    trainDot.setAttribute("opacity", "0.6");
                } else {
                    trainDot.setAttribute("stroke-width", "3");
                    trainDot.setAttribute("opacity", "1");
                }
                
                markerGroup.appendChild(trainDot);

                const trainLabel = document.createElementNS("http://www.w3.org/2000/svg", "text");
                trainLabel.setAttribute("x", cx);
                trainLabel.setAttribute("y", cy - 22);
                trainLabel.setAttribute("fill", "#ffffff");
                trainLabel.setAttribute("font-size", "20px");
                trainLabel.setAttribute("font-weight", "bold");
                trainLabel.setAttribute("text-anchor", "middle");
                trainLabel.setAttribute("style", "text-shadow: 2px 2px 3px rgba(0,0,0,0.85); pointer-events: none;");
                trainLabel.textContent = train.trainId;
                markerGroup.appendChild(trainLabel);

                targetLayer.appendChild(markerGroup);
            }
        });
    }, [activeTrains, stationCoordsRegistry, isMapReady]);

    return (
        <div style={{ 
            width: '100%', 
            height: '700px', 
            backgroundColor: '#373737', 
            borderRadius: '8px',
            border: '2px solid #555',
            overflow: 'hidden' 
        }}>
            <TransformWrapper
                initialScale={0.8}
                minScale={0.3}
                maxScale={5}
                centerOnInit={true}
                wheel={{ step: 0.1 }}
            >
                <TransformComponent wrapperStyle={{ width: "100%", height: "100%" }}>
                    <div 
                        ref={mapContainerRef} 
                        style={{ width: '100%', height: '100%' }} 
                    />
                </TransformComponent>
            </TransformWrapper>
        </div>
    );
}